    if (qt === "hit") {
      pYes = ctx.helpers.bsOneTouch(mCtx);
    } else if (qt === "above") {
      pYes = ctx.helpers.bsAbove(mCtx);
    } else if (qt === "below") {
      pYes = 1 - ctx.helpers.bsAbove(mCtx);
    } else if (qt === "range") {
      pYes = ctx.helpers.bsRange(mCtx);
    } else {
      return { question: market.question, questionType: qt, decision: "hold", reason: "unsupported type" };
    }
    const rsiShift = (rsi14 - 50) / 200;
