      distDamper = 1 / (1 + dist * 5);
    } catch (_) {}
    const shift = (rsiShift + momShift + volShift) * distDamper;
    const pYesAdj = sigmoid(logit(Math.min(Math.max(pYes, 1e-6), 1 - 1e-6)) + shift);
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYesAdj);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];
    const common = { question: market.question, questionType: qt, expiryDate: market.expiryDate, hoursToExpiry: Math.round(market.hoursToExpiry), pYesBS: +pYes.toFixed(4), pYesAdj: +pYesAdj.toFixed(4), fairPrice: +best.fairPrice.toFixed(4), marketPrice: +best.marketPrice.toFixed(4), edge: +best.edge.toFixed(4), rsi: +rsi14.toFixed(1), momentumSign };
    if (best.edge < THRESHOLD) return { ...common, decision: "hold" };
